                <a href="#" className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center hover:bg-blue-600 transition-colors">
                  <i className="fab fa-facebook-f"></i>
                </a>
              </div>
            </div>

            <div>
              <h4 className="font-bold text-lg mb-6">Discover</h4>
              <ul className="space-y-4 text-slate-400">
                <li><button onClick={() => setView('profile')} className="hover:text-white transition-colors">Artist Profile</button></li>
                <li><button onClick={() => setView('songs')} className="hover:text-white transition-colors">Latest Albums</button></li>
