import React, { useState, useEffect } from 'react';

interface LoginProps {
  onLogin: (username: string) => void;
}

export const AdminLogin: React.FC<LoginProps> = ({ onLogin }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    // Initialize default admin if no users exist
    const users = JSON.parse(localStorage.getItem('anisapop_users') || '[]');
    if (users.length === 0) {
      users.push({ username: 'admin', password: 'password123' });
      localStorage.setItem('anisapop_users', JSON.stringify(users));
    }
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    const users = JSON.parse(localStorage.getItem('anisapop_users') || '[]');

    if (isSignUp) {
      if (password !== confirmPassword) {
        setError('Passwords do not match');
        return;
      }
      if (users.find((u: any) => u.username === username)) {
        setError('Username already exists');
        return;
      }

      users.push({ username, password });
      localStorage.setItem('anisapop_users', JSON.stringify(users));
      setSuccess('Account created! You can now login.');
      setIsSignUp(false);
      setPassword('');
      setConfirmPassword('');
    } else {
      const user = users.find((u: any) => u.username === username && u.password === password);
      if (user) {
        onLogin(username);
      } else {
        setError('Invalid username or password');
      }
    }
  };

  return (
    <div className="min-h-[70vh] flex items-center justify-center px-4 py-12">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-xl border border-slate-100 p-10 transition-all duration-300">
