          Secure AnisaPop Management Gateway
        </p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Song, Artist } from '../../types';

interface MusicManagerProps {
  artist: Artist;
  onUpdateTracks: (tracks: Song[]) => void;
  onBack: () => void;
}

export const MusicManager: React.FC<MusicManagerProps> = ({ artist, onUpdateTracks, onBack }) => {
  const [tracks, setTracks] = useState<Song[]>([...artist.popularTracks]);
  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [formData, setFormData] = useState<Song>({ title: '', duration: '', year: new Date().getFullYear(), streams: '' });
  const [isAdding, setIsAdding] = useState(false);

  const handleEdit = (index: number) => {
    setEditingIndex(index);
    setFormData(tracks[index]);
    setIsAdding(false);
  };

  const handleDelete = (index: number) => {
    if (window.confirm('Are you sure you want to delete this track?')) {
      const newTracks = tracks.filter((_, i) => i !== index);
      setTracks(newTracks);
      onUpdateTracks(newTracks);
    }
  };

  const handleSave = () => {
    if (!formData.title || !formData.duration) return;

    let newTracks: Song[];
    if (editingIndex !== null) {
      newTracks = tracks.map((t, i) => (i === editingIndex ? formData : t));
    } else {
      newTracks = [...tracks, formData];
    }

    setTracks(newTracks);
    onUpdateTracks(newTracks);
    setEditingIndex(null);
    setIsAdding(false);
    setFormData({ title: '', duration: '', year: new Date().getFullYear(), streams: '' });
  };

  const cancelEdit = () => {
    setEditingIndex(null);
    setIsAdding(false);
    setFormData({ title: '', duration: '', year: new Date().getFullYear(), streams: '' });
  };

  return (
    <div className="p-8 bg-white rounded-3xl border border-slate-100 shadow-sm animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <button onClick={onBack} className="text-slate-400 hover:text-indigo-600 mb-2 flex items-center gap-2 text-sm font-medium transition-colors">
            <i className="fas fa-arrow-left"></i> Back to Dashboard
          </button>
          <h2 className="text-3xl font-bold text-slate-900 font-serif">Manage Tracks</h2>
          <p className="text-slate-500">Edit or update the popular tracklist for {artist.name}</p>
        </div>
        {!isAdding && editingIndex === null && (
          <button 
            onClick={() => setIsAdding(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-100"
          >
            <i className="fas fa-plus"></i> Add New Track
          </button>
        )}
      </div>

      {(isAdding || editingIndex !== null) && (
        <div className="mb-10 p-6 bg-slate-50 rounded-2xl border border-indigo-100">
          <h3 className="font-bold text-slate-900 mb-6">{isAdding ? 'Add New Track' : 'Edit Track'}</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Track Title</label>
              <input 
                type="text" 
                value={formData.title} 
                onChange={e => setFormData({...formData, title: e.target.value})}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                placeholder="e.g. Blank Space"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Duration</label>
              <input 
                type="text" 
                value={formData.duration} 
                onChange={e => setFormData({...formData, duration: e.target.value})}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                placeholder="e.g. 3:51"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Release Year</label>
              <input 
                type="number" 
                value={formData.year} 
                onChange={e => setFormData({...formData, year: parseInt(e.target.value) || 2024})}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Streams (Label)</label>
              <input 
                type="text" 
                value={formData.streams || ''} 
                onChange={e => setFormData({...formData, streams: e.target.value})}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                placeholder="e.g. 1.2B"
              />
            </div>
          </div>
          <div className="flex justify-end gap-3">
            <button onClick={cancelEdit} className="px-6 py-2 rounded-lg text-slate-500 font-bold hover:bg-slate-200 transition-all">Cancel</button>
            <button onClick={handleSave} className="px-8 py-2 rounded-lg bg-indigo-600 text-white font-bold hover:bg-indigo-700 transition-all shadow-md">
              {editingIndex !== null ? 'Save Changes' : 'Add Track'}
            </button>
          </div>
        </div>
      )}

      <div className="overflow-x-auto">
        <table className="w-full">
          <thead>
            <tr className="border-b border-slate-100 text-left">
              <th className="pb-4 text-xs font-bold text-slate-400 uppercase">Track</th>
              <th className="pb-4 text-xs font-bold text-slate-400 uppercase">Year</th>
              <th className="pb-4 text-xs font-bold text-slate-400 uppercase">Duration</th>
              <th className="pb-4 text-xs font-bold text-slate-400 uppercase">Streams</th>
              <th className="pb-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {tracks.map((track, idx) => (
              <tr key={idx} className="group hover:bg-slate-50/50 transition-colors">
                <td className="py-4">
                  <span className="font-bold text-slate-900">{track.title}</span>
                </td>
                <td className="py-4 text-slate-500 text-sm">{track.year}</td>
                <td className="py-4 text-slate-500 text-sm">{track.duration}</td>
                <td className="py-4 text-slate-500 text-sm">{track.streams || '-'}</td>
                <td className="py-4 text-right space-x-2">
                  <button 
                    onClick={() => handleEdit(idx)}
                    className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"
                    title="Edit Track"
                  >
                    <i className="fas fa-edit"></i>
                  </button>
                  <button 
                    onClick={() => handleDelete(idx)}
                    className="p-2 text-slate-400 hover:text-rose-500 transition-colors"
                    title="Delete Track"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Navigation } from './components/Navigation';
import { Hero } from './components/Hero';
import { ProfileView } from './components/ProfileView';
import { MusicView } from './components/MusicView';
import { GalleryView } from './components/GalleryView';
import { NewsView } from './components/NewsView';
import { ContactView } from './components/ContactView';
import { AdminLogin } from './components/Admin/Login';
import { AdminDashboard } from './components/Admin/Dashboard';
import { MusicManager } from './components/Admin/MusicManager';
import { fetchArtistData } from './services/geminiService';
import { Artist, ViewType, Song } from './types';
import { INITIAL_ARTIST_NAME } from './constants';

type AdminViewType = 'dashboard' | 'music-crud';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('home');
  const [adminView, setAdminView] = useState<AdminViewType>('dashboard');
  const [artist, setArtist] = useState<Artist | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState('');

  const loadArtist = useCallback(async (name: string) => {
    setLoading(true);
    setError(null);
    try {
      const data = await fetchArtistData(name);
      setArtist(data);
    } catch (err) {
      setError("Failed to fetch artist data. Please check your API key or try another artist.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadArtist(INITIAL_ARTIST_NAME);
  }, [loadArtist]);

  const handleSearch = (name: string) => {
    loadArtist(name);
  };

  const handleUpdateTracks = (newTracks: Song[]) => {
    if (artist) {
      setArtist({ ...artist, popularTracks: newTracks });
    }
  };

  const handleLogin = (username: string) => {
    setIsAuthenticated(true);
    setCurrentUser(username);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-slate-500">
          <div className="w-16 h-16 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
          <p className="text-xl font-medium animate-pulse">Consulting the oracle of Pop...</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="max-w-2xl mx-auto py-20 px-4 text-center">
          <div className="w-20 h-20 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6">
            <i className="fas fa-exclamation-triangle text-3xl"></i>
          </div>
          <h2 className="text-2xl font-bold mb-4">Oops! Something went wrong</h2>
          <p className="text-slate-500 mb-8">{error}</p>
          <button 
            onClick={() => loadArtist(INITIAL_ARTIST_NAME)}
            className="bg-indigo-600 text-white px-8 py-3 rounded-full font-bold"
          >
            Try Taylor Swift
          </button>
        </div>
      );
    }

    if (!artist) return null;

    switch (currentView) {
      case 'home':
        return (
          <>
            <Hero artist={artist} onExplore={() => setView('profile')} />
            <ProfileView artist={artist} />
            <MusicView artist={artist} />
            <NewsView artist={artist} />
          </>
        );
      case 'profile':
        return <ProfileView artist={artist} />;
      case 'songs':
        return <MusicView artist={artist} />;
      case 'gallery':
        return <GalleryView artist={artist} />;
      case 'news':
        return <NewsView artist={artist} />;
      case 'contact':
        return <ContactView />;
      case 'admin':
        if (!isAuthenticated) {
          return <AdminLogin onLogin={handleLogin} />;
        }

        if (adminView === 'music-crud') {
          return <MusicManager artist={artist} onUpdateTracks={handleUpdateTracks} onBack={() => setAdminView('dashboard')} />;
        }

        return (
          <AdminDashboard 
            artist={artist} 
            user={currentUser}
            onLogout={() => setIsAuthenticated(false)} 
            onManageMusic={() => setAdminView('music-crud')}
            onSelectArtist={(name) => {
              handleSearch(name);
              setView('home');
            }} 
          />
        );
      default:
        return <Hero artist={artist} onExplore={() => setView('profile')} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 selection:bg-indigo-100 selection:text-indigo-900">
      <Navigation currentView={currentView} setView={setView} onSearch={handleSearch} />

      {isAuthenticated && currentView !== 'admin' && (
        <div className="bg-indigo-600 text-white py-2 px-4 text-center text-xs font-bold uppercase tracking-widest animate-fade-in shadow-lg">
          Logged in as <span className="font-bold">{currentUser}</span> • <button onClick={() => { setView('admin'); setAdminView('dashboard'); }} className="underline">Dashboard</button>
        </div>
      )}

      <main className="transition-opacity duration-300 min-h-[70vh]">
        {renderContent()}
      </main>

      <footer className="bg-slate-900 text-white py-16 border-t border-slate-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-12 mb-12">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center gap-2 mb-6">
                <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
                  <i className="fas fa-bolt text-xl"></i>
                </div>
                <span className="text-3xl font-bold tracking-tight font-serif">AnisaPop</span>
              </div>
              <p className="text-slate-400 max-w-sm mb-6">
                Your ultimate digital destination for the world's most influential pop artists. 
                Powered by Gemini AI for real-time insights and data.
              </p>
              <div className="flex gap-4">
                <a href="#" className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center hover:bg-indigo-600 transition-colors">
                  <i className="fab fa-twitter"></i>
                </a>
                <a href="#" className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center hover:bg-rose-600 transition-colors">
                  <i className="fab fa-instagram"></i>
                </a>
                <a href="#" className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center hover:bg-red-600 transition-colors">
                  <i className="fab fa-youtube"></i>
                </a>
                <a href="#" className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center hover:bg-blue-600 transition-colors">
                  <i className="fab fa-facebook-f"></i>
                </a>
              </div>
            </div>

            <div>
              <h4 className="font-bold text-lg mb-6">Discover</h4>
              <ul className="space-y-4 text-slate-400">
                <li><button onClick={() => setView('profile')} className="hover:text-white transition-colors">Artist Profile</button></li>
                <li><button onClick={() => setView('songs')} className="hover:text-white transition-colors">Latest Albums</button></li>
                <li><button onClick={() => setView('songs')} className="hover:text-white transition-colors">Popular Tracks</button></li>
                <li><button onClick={() => setView('news')} className="hover:text-white transition-colors">Tour Dates</button></li>
              </ul>
            </div>

            <div>
              <h4 className="font-bold text-lg mb-6">Internal</h4>
              <ul className="space-y-4 text-slate-400">
                <li><button onClick={() => { setView('admin'); setAdminView('dashboard'); }} className="hover:text-white transition-colors flex items-center gap-2">
                  <i className="fas fa-user-shield text-xs"></i> Admin Panel
                </button></li>
                <li><a href="#" className="hover:text-white transition-colors">Fan Club</a></li>
                <li><a href="#" className="hover:text-white transition-colors">Forum</a></li>
                <li><a href="#" className="hover:text-white transition-colors">Store</a></li>
              </ul>
            </div>
          </div>

          <div className="pt-8 border-t border-slate-800 flex flex-col md:flex-row justify-between items-center gap-4 text-sm text-slate-500">
            <p>&copy; 2024 AnisaPop Media Group. All rights reserved.</p>
            <div className="flex gap-8">
              <a href="#" className="hover:text-slate-300">Privacy Policy</a>
              <a href="#" className="hover:text-slate-300">Terms of Service</a>
              <a href="#" className="hover:text-slate-300">Cookies</a>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

