import { GoogleGenAI, Type } from "@google/genai";
import { Artist } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const artistSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING },
    genre: { type: Type.STRING },
    bio: { type: Type.STRING },
    origin: { type: Type.STRING },
    activeSince: { type: Type.STRING },
    themeColor: { 
      type: Type.STRING, 
      description: "A hex color code that represents the artist's brand or aesthetic (e.g. #ff0000 for Taylor Swift's Red era, #a855f7 for Prince)." 
    },
    stats: {
      type: Type.OBJECT,
      properties: {
        monthlyListeners: { type: Type.STRING },
        globalRank: { type: Type.STRING },
        followers: { type: Type.STRING },
      },
      required: ["monthlyListeners", "globalRank", "followers"]
    },
    popularTracks: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          duration: { type: Type.STRING },
          year: { type: Type.NUMBER },
          streams: { type: Type.STRING }
        },
        required: ["title", "duration", "year"]
      }
    },
    albums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          year: { type: Type.NUMBER },
          description: { type: Type.STRING }
        },
        required: ["title", "year"]
      }
    },
    achievements: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          award: { type: Type.STRING },
          year: { type: Type.NUMBER },
          category: { type: Type.STRING }
        },
        required: ["award", "year"]
      }
    },
    news: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          date: { type: Type.STRING },
          excerpt: { type: Type.STRING },
          category: { type: Type.STRING }
        },
        required: ["title", "date", "excerpt"]
      }
    }
  },
  required: ["name", "genre", "bio", "popularTracks", "albums", "stats", "themeColor"]
};

export const fetchArtistData = async (artistName: string): Promise<Artist> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide comprehensive fanpage information for the music artist: ${artistName}. 
      Include a bio, origin, active since date, a representative themeColor hex code, stats (listeners, rank), 5 popular tracks, 3 notable albums, 
      3 major achievements, and 3 recent news/updates items. 
      Ensure news items are categorized as 'Update', 'Concert', 'Release', or 'Award'.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: artistSchema,
      },
    });

    const data = JSON.parse(response.text);

    // Add image placeholders and enrich data
    return {
      ...data,
      imageUrl: `https://picsum.photos/seed/${artistName.replace(' ', '')}/1200/800`,
      albums: data.albums.map((album: any, idx: number) => ({
        ...album,
        coverUrl: `https://picsum.photos/seed/${artistName.replace(' ', '')}album${idx}/600/600`
      }))
    };
  } catch (error) {
    console.error("Error fetching artist data:", error);
    throw error;
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Navigation } from './components/Navigation';
