import { Artist, ViewType, Song } from './types';
import { INITIAL_ARTIST_NAME } from './constants';

type AdminViewType = 'dashboard' | 'music-crud';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('home');
  const [adminView, setAdminView] = useState<AdminViewType>('dashboard');
  const [artist, setArtist] = useState<Artist | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState('');

  // Update theme colors when artist changes
  useEffect(() => {
    if (artist?.themeColor) {
      document.documentElement.style.setProperty('--artist-accent', artist.themeColor);

      // Convert Hex to RGB for gradients
      const hex = artist.themeColor.replace('#', '');
      const r = parseInt(hex.substring(0, 2), 16);
      const g = parseInt(hex.substring(2, 4), 16);
      const b = parseInt(hex.substring(4, 6), 16);
      if (!isNaN(r) && !isNaN(g) && !isNaN(b)) {
        document.documentElement.style.setProperty('--artist-accent-rgb', `${r}, ${g}, ${b}`);
      }
    }
  }, [artist]);

  const loadArtist = useCallback(async (name: string) => {
    setLoading(true);
    setError(null);
    try {
      const data = await fetchArtistData(name);
      setArtist(data);
    } catch (err) {
      setError("Failed to fetch artist data. Please check your API key or try another artist.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadArtist(INITIAL_ARTIST_NAME);
  }, [loadArtist]);

  const handleSearch = (name: string) => {
    loadArtist(name);
  };

  const handleUpdateTracks = (newTracks: Song[]) => {
    if (artist) {
      setArtist({ ...artist, popularTracks: newTracks });
    }
  };

  const handleLogin = (username: string) => {
    setIsAuthenticated(true);
    setCurrentUser(username);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-slate-500">
          <div className="w-16 h-16 border-4 border-slate-800 border-t-[var(--artist-accent)] rounded-full animate-spin mb-4 transition-colors duration-500"></div>
          <p className="text-xl font-medium animate-pulse accent-text uppercase tracking-widest text-xs font-bold">Synchronizing Beats...</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="max-w-2xl mx-auto py-20 px-4 text-center">
          <div className="w-20 h-20 bg-rose-950 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6 border border-rose-500/20">
            <i className="fas fa-exclamation-triangle text-3xl"></i>
          </div>
          <h2 className="text-2xl font-bold mb-4 text-white">Playback Error</h2>
          <p className="text-slate-500 mb-8">{error}</p>
          <button 
            onClick={() => loadArtist(INITIAL_ARTIST_NAME)}
            className="accent-bg text-slate-950 px-8 py-3 rounded-full font-bold shadow-lg"
          >
            Retry Studio Session
          </button>
        </div>
      );
    }

    if (!artist) return null;

    switch (currentView) {
      case 'home':
        return (
          <>
            <Hero artist={artist} onExplore={() => setView('profile')} />
            <ProfileView artist={artist} />
            <MusicView artist={artist} />
            <NewsView artist={artist} />
          </>
        );
      case 'profile':
        return <ProfileView artist={artist} />;
      case 'songs':
        return <MusicView artist={artist} />;
      case 'gallery':
        return <GalleryView artist={artist} />;
      case 'news':
        return <NewsView artist={artist} />;
      case 'contact':
        return <ContactView />;
      case 'admin':
        if (!isAuthenticated) {
          return <AdminLogin onLogin={handleLogin} />;
        }

        if (adminView === 'music-crud') {
          return <MusicManager artist={artist} onUpdateTracks={handleUpdateTracks} onBack={() => setAdminView('dashboard')} />;
        }

        return (
          <AdminDashboard 
            artist={artist} 
            user={currentUser}
            onLogout={() => setIsAuthenticated(false)} 
            onManageMusic={() => setAdminView('music-crud')}
            onSelectArtist={(name) => {
              handleSearch(name);
              setView('home');
            }} 
          />
        );
      default:
        return <Hero artist={artist} onExplore={() => setView('profile')} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 selection:bg-[var(--artist-accent)] selection:text-slate-950">
      <Navigation currentView={currentView} setView={setView} onSearch={handleSearch} />

      {isAuthenticated && currentView !== 'admin' && (
        <div className="accent-bg text-slate-950 py-2 px-4 text-center text-xs font-black uppercase tracking-widest animate-fade-in shadow-2xl">
          System Admin: <span className="font-bold">{currentUser}</span> • <button onClick={() => { setView('admin'); setAdminView('dashboard'); }} className="underline decoration-2 underline-offset-2">Control Panel</button>
        </div>
      )}

      <main className="transition-opacity duration-300 min-h-[70vh]">
        {renderContent()}
      </main>

      <footer className="bg-slate-950 text-white py-16 border-t border-white/5">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-12 mb-12">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center gap-3 mb-6 group">
