import { GoogleGenAI, Type } from "@google/genai";
import { Artist } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const artistSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING },
    genre: { type: Type.STRING },
    bio: { type: Type.STRING },
    origin: { type: Type.STRING },
    activeSince: { type: Type.STRING },
    officialUrl: { 
      type: Type.STRING, 
      description: "A real URL to the artist's official website, Spotify profile, or verified fan hub." 
    },
    imageUrl: { 
      type: Type.STRING, 
      description: "A DIRECT link to a high-quality photo of the artist from a reliable source." 
    },
    themeColor: { 
      type: Type.STRING, 
      description: "A SOFT, LIGHT PASTEL hex color (e.g., #E2E8F0, #FCE7F3, #F0FDFA). ABSOLUTELY NO NEON, NO DARK COLORS." 
    },
    stats: {
      type: Type.OBJECT,
      properties: {
        monthlyListeners: { type: Type.STRING },
        globalRank: { type: Type.STRING },
        followers: { type: Type.STRING },
      },
      required: ["monthlyListeners", "globalRank", "followers"]
    },
    popularTracks: {
      type: Type.ARRAY,
      minItems: 5,
      maxItems: 5,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          duration: { type: Type.STRING },
          year: { type: Type.NUMBER },
          streams: { type: Type.STRING }
        },
        required: ["title", "duration", "year"]
      }
    },
    albums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          year: { type: Type.NUMBER },
          coverUrl: { type: Type.STRING, description: "Direct URL to the actual album cover image." },
          description: { type: Type.STRING }
        },
        required: ["title", "year", "coverUrl"]
      }
    },
    achievements: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          award: { type: Type.STRING },
          year: { type: Type.NUMBER },
          category: { type: Type.STRING }
        },
        required: ["award", "year"]
      }
    },
    news: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          date: { type: Type.STRING },
          excerpt: { type: Type.STRING },
          category: { type: Type.STRING }
        },
        required: ["title", "date", "excerpt"]
      }
    }
  },
  required: ["name", "genre", "bio", "officialUrl", "imageUrl", "popularTracks", "albums", "stats", "themeColor"]
};

export const fetchArtistData = async (artistName: string): Promise<Artist> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for music artist: ${artistName}. 
      1. Find official URL & real image URLs.
      2. Exactly TOP 5 sounds.
      3. CRITICAL: Theme color must be a SOFT, AIRY PASTEL. No neon, no dark navy, no black themes.
      4. Sophisticated bio and career highlights.`,
      config: {
        tools: [{googleSearch: {}}],
        responseMimeType: "application/json",
        responseSchema: artistSchema,
      },
    });

    const data = JSON.parse(response.text);
    const artistTag = encodeURIComponent(data.name.toLowerCase());

    const finalImageUrl = (data.imageUrl && data.imageUrl.startsWith('http')) 
      ? data.imageUrl 
      : `https://loremflickr.com/1200/1600/${artistTag},singer,celebrity/all`;

    return {
      ...data,
      imageUrl: finalImageUrl,
      albums: data.albums.map((album: any, idx: number) => ({
        ...album,
        coverUrl: (album.coverUrl && album.coverUrl.startsWith('http'))
          ? album.coverUrl
          : `https://loremflickr.com/800/800/${artistTag},${encodeURIComponent(album.title)},album/all?lock=${idx}`
      }))
    };
  } catch (error) {
    console.error("Error fetching artist data:", error);
    throw error;
  }
};

