  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for music artist: ${artistName}. 
      1. CRITICAL: Find the ACTUAL official website, Instagram, and Twitter URLs.
      2. Write a DETAILED, multi-paragraph biography (at least 300 words) that fills the page beautifully.
      3. Use the googleSearch tool for real-time accurate URLs and high-quality official image assets.
      4. Theme color must be a soft blue-gray or beige-brown.`,
      config: {
