const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const artistSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "The stage name or common name of the artist." },
    fullName: { type: Type.STRING, description: "The official birth name or legal full name of the artist." },
    genre: { type: Type.STRING },
    bio: { type: Type.STRING, description: "A detailed, multi-paragraph biography including early life, career breakthroughs, and current cultural impact. At least 300 words." },
    origin: { type: Type.STRING },
    activeSince: { type: Type.STRING },
    officialUrl: { 
      type: Type.STRING, 
      description: "The direct URL to the artist's official website." 
    },
    instagramUrl: { 
      type: Type.STRING, 
      description: "The direct URL to the artist's official Instagram profile." 
    },
    twitterUrl: { 
      type: Type.STRING, 
      description: "The direct URL to the artist's official Twitter/X profile." 
    },
    imageUrl: { 
      type: Type.STRING, 
      description: "A DIRECT link to an ACTUAL, HIGH-RESOLUTION official photo of the artist from a reliable source like Wikimedia or a press kit." 
    },
    themeColor: { 
      type: Type.STRING, 
      description: "A SOFT, MODERN blue-gray or cream-brown hex code." 
    },
    stats: {
      type: Type.OBJECT,
      properties: {
        monthlyListeners: { type: Type.STRING },
        globalRank: { type: Type.STRING },
        followers: { type: Type.STRING },
      },
      required: ["monthlyListeners", "globalRank", "followers"]
    },
    popularTracks: {
      type: Type.ARRAY,
      minItems: 5,
      maxItems: 5,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          duration: { type: Type.STRING },
          year: { type: Type.NUMBER },
          streams: { type: Type.STRING }
        },
        required: ["title", "duration", "year"]
      }
    },
    albums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          year: { type: Type.NUMBER },
          coverUrl: { type: Type.STRING, description: "A DIRECT link to the actual, official album cover image." },
          description: { type: Type.STRING }
        },
        required: ["title", "year", "coverUrl"]
      }
    },
    achievements: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          award: { type: Type.STRING },
