          date: { type: Type.STRING },
          excerpt: { type: Type.STRING },
          category: { type: Type.STRING }
        },
        required: ["title", "date", "excerpt"]
      }
    }
  },
  required: ["name", "fullName", "genre", "bio", "officialUrl", "instagramUrl", "imageUrl", "popularTracks", "albums", "stats", "themeColor"]
};

export const fetchArtistData = async (artistName: string): Promise<Artist> => {
  const normalizedSearch = artistName.toLowerCase().trim();

  // Return mock data immediately if available to ensure "Complete Data" for standard examples
  if (MOCK_ARTISTS[normalizedSearch]) {
    console.debug(`Returning cached mock data for: ${artistName}`);
    return MOCK_ARTISTS[normalizedSearch];
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for music artist: ${artistName}. 
      1. CRITICAL: Provide the complete data including their legal full name, a high-quality official photo, and a full list of major albums.
      2. Find the ACTUAL official website and social media handles.
      3. Write a long, comprehensive biography (at least 300 words).
      4. Use the googleSearch tool to find the most accurate real-time data and direct image links for profile and album covers.
      5. DO NOT use placeholder images. Use direct links to the assets found via search.`,
      config: {
        tools: [{googleSearch: {}}],
        responseMimeType: "application/json",
        responseSchema: artistSchema,
      },
    });

    const data = JSON.parse(response.text);
    return data;
  } catch (error) {
    console.error("Error fetching artist data:", error);
    throw error;
  }
};

