import React, { useState, useEffect } from 'react';
import { Artist } from '../types';

interface HeroProps {
  artist: Artist;
  onExplore: () => void;
}

export const Hero: React.FC<HeroProps> = ({ artist, onExplore }) => {
  const [imgLoaded, setImgLoaded] = useState(false);
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
    setImgLoaded(false);
    setImgError(false);
  }, [artist.imageUrl]);

  // Use artist's primary image with a fallback system
  const displayImageUrl = artist.imageUrl || 'https://via.placeholder.com/800x1200?text=Artist+Portrait';

  return (
    <div className="relative min-h-[90vh] w-full flex items-center pt-10">
      <div className="max-w-7xl mx-auto px-6 w-full grid grid-cols-1 lg:grid-cols-12 gap-20 items-center relative z-10">
        <div className="lg:col-span-7 space-y-10">
          <div className="inline-flex items-center gap-3 px-6 py-2 bg-white rounded-full shadow-sm border border-slate-200/50">
            <span className="w-2 h-2 rounded-full bg-[var(--artist-accent)]"></span>
            <span className="text-[9px] font-black uppercase tracking-[0.4em] text-slate-500">Trending Now</span>
          </div>

          <h1 className="text-8xl md:text-[120px] font-black text-[#0f172a] font-serif leading-[0.85] tracking-tighter title-reveal">
            {artist.name.split(' ').map((word, i) => (
              <span key={i} className="block">{word}</span>
            ))}
          </h1>

          <p className="text-xl md:text-2xl text-slate-600 max-w-xl leading-relaxed font-light italic border-l-4 border-slate-300 pl-8">
            "{artist.bio.split('.')[0]}."
          </p>

          <div className="flex flex-wrap gap-6 pt-4">
            <button
              onClick={onExplore}
              className="btn-primary px-16 py-5 rounded-full font-black text-xs uppercase tracking-widest shadow-xl active:scale-95 transition-all"
            >
              Enter the Hub <i className="fas fa-arrow-right ml-4"></i>
            </button>
            <a 
              href={artist.officialUrl} 
              target="_blank" 
              rel="noopener noreferrer"
              className="px-16 py-5 rounded-full font-black text-xs uppercase tracking-widest bg-white border border-slate-200 text-[#0f172a] hover:bg-slate-50 transition-all flex items-center gap-4 shadow-sm"
            >
              Official Profile
            </a>
          </div>
        </div>

        <div className="lg:col-span-5 relative">
          <div className="relative w-full aspect-[3/4] rounded-[3.5rem] overflow-hidden shadow-2xl border-[12px] border-white group bg-slate-100">
             {!imgLoaded && !imgError && (
               <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-10 h-10 border-4 border-slate-200 border-t-[var(--artist-accent)] rounded-full animate-spin"></div>
               </div>
             )}
             <img
              src={imgError ? 'https://via.placeholder.com/800x1200?text=Artist+Archive' : displayImageUrl}
              alt={artist.name}
              onLoad={() => setImgLoaded(true)}
              onError={() => {
                setImgError(true);
                setImgLoaded(true);
              }}
              className={`w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000 ${imgLoaded ? 'loaded' : 'opacity-0'}`}
              style={{ opacity: imgLoaded ? 1 : 0 }}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-[#0f172a]/30 via-transparent to-transparent"></div>
          </div>

          <div className="absolute -bottom-8 -left-10 glass p-8 rounded-[2.5rem] shadow-2xl max-w-[280px] border-slate-200">
             <div className="space-y-6">
                <div>
                    <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1">Global Chart Pos</span>
                    <span className="text-[var(--artist-accent)] font-black text-2xl font-serif tracking-tighter">#{artist.stats.globalRank}</span>
                </div>
                <div className="h-px bg-slate-100"></div>
                <div>
                    <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1">Monthly Reach</span>
                    <span className="text-[#0f172a] font-black text-2xl font-serif tracking-tighter">{artist.stats.monthlyListeners}</span>
                </div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

