        },
        required: ["title", "duration", "year"]
      }
    },
    albums: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          year: { type: Type.NUMBER },
          coverUrl: { type: Type.STRING },
          description: { type: Type.STRING }
        },
        required: ["title", "year", "coverUrl"]
      }
    },
    achievements: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          award: { type: Type.STRING },
          year: { type: Type.NUMBER },
          category: { type: Type.STRING }
        },
        required: ["award", "year"]
      }
    },
    news: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
